using System;
using System.IO;
using System.Reflection;
using System.Linq;
using System.Collections.Generic;

class Inspector
{
    static void Main()
    {
        var dllPaths = new[]
        {
            "/home/runner/.nuget/packages/microsoft.agents.ai/1.5.0/lib/net10.0/Microsoft.Agents.AI.dll",
            "/home/runner/.nuget/packages/microsoft.extensions.ai.abstractions/10.5.1/lib/net10.0/Microsoft.Extensions.AI.Abstractions.dll",
            "/home/runner/.nuget/packages/microsoft.extensions.ai/10.5.1/lib/net10.0/Microsoft.Extensions.AI.dll"
        };

        foreach (var dllPath in dllPaths)
        {
            if (!File.Exists(dllPath))
            {
                Console.WriteLine($"❌ Not found: {dllPath}\n");
                continue;
            }

            Console.WriteLine($"\n{'='*70}");
            Console.WriteLine($"DLL: {Path.GetFileName(dllPath)}");
            Console.WriteLine($"Path: {dllPath}");
            Console.WriteLine($"{'='*70}\n");

            try
            {
                var asm = Assembly.LoadFrom(dllPath);
                var types = asm.GetExportedTypes();

                // Key types to look for
                var keyTypeNames = new[] 
                { 
                    "ChatClientAgent", 
                    "AgentInvokeOptions", 
                    "ChatMessage",
                    "ChatOptions",
                    "AIFunction",
                    "AIFunctionFactory",
                    "IChatClient"
                };

                foreach (var typeName in keyTypeNames)
                {
                    var type = types.FirstOrDefault(t => t.Name == typeName);
                    if (type != null)
                    {
                        Console.WriteLine($"📌 Type: {type.FullName}");
                        Console.WriteLine($"   Namespace: {type.Namespace}");
                        Console.WriteLine($"   BaseType: {type.BaseType?.Name ?? "object"}");

                        if (type.IsClass || type.IsInterface)
                        {
                            // Constructors
                            var constructors = type.GetConstructors();
                            if (constructors.Length > 0)
                            {
                                Console.WriteLine($"   Constructors:");
                                foreach (var ctor in constructors)
                                {
                                    var @params = string.Join(", ", ctor.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
                                    Console.WriteLine($"      - {ctor.DeclaringType?.Name}({@params})");
                                }
                            }

                            // Methods
                            var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static | BindingFlags.DeclaredOnly)
                                .Where(m => !m.IsSpecialName)
                                .ToList();

                            if (methods.Count > 0)
                            {
                                Console.WriteLine($"   Methods:");
                                foreach (var method in methods.Take(15))
                                {
                                    var @params = string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
                                    var returnType = method.ReturnType.Name;
                                    Console.WriteLine($"      - {returnType} {method.Name}({@params})");
                                }
                                if (methods.Count > 15) Console.WriteLine($"      ... and {methods.Count - 15} more");
                            }

                            // Properties
                            var props = type.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static | BindingFlags.DeclaredOnly);
                            if (props.Length > 0)
                            {
                                Console.WriteLine($"   Properties:");
                                foreach (var prop in props.Take(10))
                                {
                                    Console.WriteLine($"      - {prop.PropertyType.Name} {prop.Name} {{ {(prop.CanRead ? "get;" : "")} {(prop.CanWrite ? "set;" : "")} }}");
                                }
                                if (props.Length > 10) Console.WriteLine($"      ... and {props.Length - 10} more");
                            }
                        }
                        Console.WriteLine();
                    }
                }
            }
            catch (Exception ex)
            {
                Console.WriteLine($"❌ Error loading {Path.GetFileName(dllPath)}: {ex.Message}\n");
            }
        }
    }
}
