using System.Reflection;

var meaiAsm = typeof(Microsoft.Extensions.AI.AIFunctionFactory).Assembly;
Console.WriteLine($"MEAI Assembly: {meaiAsm.GetName().Name} v{meaiAsm.GetName().Version}");
Console.WriteLine("\n=== All public types in MEAI ===");
foreach (var t in meaiAsm.GetExportedTypes().OrderBy(x => x.Name))
    Console.WriteLine($"  {t.FullName}");

// Check the ChatClientBuilder
Console.WriteLine("\n=== ChatClientBuilder ===");
var builderType = meaiAsm.GetExportedTypes().FirstOrDefault(t => t.Name == "ChatClientBuilder");
if (builderType != null)
{
    foreach (var c in builderType.GetConstructors(BindingFlags.Public | BindingFlags.Instance))
        Console.WriteLine($"  Ctor({string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
    foreach (var m in builderType.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
        Console.WriteLine($"  {m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
}

// Check UseFunctionInvocation
Console.WriteLine("\n=== FunctionInvokingChatClient ===");
var ficcType = meaiAsm.GetExportedTypes().FirstOrDefault(t => t.Name == "FunctionInvokingChatClient");
if (ficcType != null)
{
    foreach (var p in ficcType.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
        Console.WriteLine($"  {p.PropertyType.Name} {p.Name}");
}
else
{
    Console.WriteLine("  Not found in this assembly");
    // Check extension methods for UseFunctionInvocation
    var extMethods = meaiAsm.GetExportedTypes()
        .SelectMany(t => t.GetMethods(BindingFlags.Public | BindingFlags.Static))
        .Where(m => m.Name.Contains("Function"))
        .ToList();
    foreach (var m in extMethods)
        Console.WriteLine($"  {m.DeclaringType!.Name}.{m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
}

// Check OpenAI chat client extension
Console.WriteLine("\n=== OpenAI extension methods ===");
var openaiExtAsm = AppDomain.CurrentDomain.GetAssemblies()
    .FirstOrDefault(a => a.GetName().Name == "Microsoft.Extensions.AI.OpenAI");
if (openaiExtAsm != null)
{
    foreach (var t in openaiExtAsm.GetExportedTypes())
    {
        Console.WriteLine($"  Type: {t.FullName}");
        foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Static | BindingFlags.DeclaredOnly))
            Console.WriteLine($"    {m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
    }
}
else
{
    // Force load it
    var oaiAsm = Assembly.LoadFrom("/home/runner/.nuget/packages/microsoft.extensions.ai.openai/9.5.0/lib/net10.0/Microsoft.Extensions.AI.OpenAI.dll");
    foreach (var t in oaiAsm.GetExportedTypes())
    {
        Console.WriteLine($"  Type: {t.FullName}");
        foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Static | BindingFlags.DeclaredOnly))
            Console.WriteLine($"    {m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
    }
}
